function calculate_total_amount(frm) {
    let total_amount = 0 ;
    let total_quantity = 0 ;
    let total_sell_amount = 0 ;
    let total_saving = 0 ;
    const costing_sheet_items = frm.doc.costing_sheet_item || [];
    
    costing_sheet_items.forEach(function(item) {
        total_amount = total_amount + item.amount;
        total_quantity = total_quantity + item.quantity;
        total_sell_amount = total_sell_amount + item.selling_amount ;
        total_saving = total_saving + item.saving ;
    });
    
    frm.set_value('total_amount', total_amount) ;
    frm.refresh_field('frm.doc.total_amount');
    
    frm.set_value('total_quantity', total_quantity) ;
    frm.refresh_field('frm.doc.total_quantity');

    frm.set_value('total_selling_amount', total_sell_amount) ;
