}).then(records => {
    if (records.length > 0){
    
        ip_uom = records[0].uom;
        ip_rate = records[0].price_list_rate;
            item.item_code = item_code;
            item.item_name = item_name;
            item.uom = ip_uom;
            item.rate = ip_rate;
            item.amount = item.quantity * item.rate;
            item.saving = item.selling_amount - item.amount ;
    }
