async function load_fabrication_list_items(frm) {
    frm.clear_table('accessory_item');
    frm.clear_table('material_summary');
    frm.clear_table('costing_sheet_item');

    frm.refresh_field('accessory_item');
    frm.refresh_field('material_summary');
    frm.refresh_field('costing_sheet_item');

    if (!frm.doc.fabrication_list) {
        calculate_total_amount(frm);
        return;
    }

    const fl_doc = await frappe.db.get_doc('Fabrication List', frm.doc.fabrication_list);

    let sales_order_doc = null;

    // Change this field name if your Fabrication List has a different sales order field
    if (fl_doc.sales_order) {
        sales_order_doc = await frappe.db.get_doc('Sales Order', fl_doc.sales_order);
    } else if (frm.doc.sales_order) {
        sales_order_doc = await frappe.db.get_doc('Sales Order', frm.doc.sales_order);
    }

    const sales_order_items = sales_order_doc ? (sales_order_doc.custom_parent_item || []) : [];

    // -------------------------------
    // Material Summary + Costing Items
    // -------------------------------
    (fl_doc.material_summary || []).forEach(row1 => {
        const so_item = find_sales_order_item(
            sales_order_items,
            row1.parent_finished_good,
            row1.material_item_uom
        );

        const rate = so_item ? flt(so_item.rate) : 0;
        const fg_uom = so_item ? so_item.fg_item_uom : null;
        const qty = fg_uom === "KG" ? flt(row1.sum_of_duct_weight) :
                    fg_uom === "SQM" ? flt(row1.sum_of_duct_area_with_seam) :
                    flt(row1.material_item_qty);
        const amount = qty * rate;

        frm.add_child('material_summary', {
            parent_finished_good: row1.parent_finished_good,
            material_item_code: row1.material_item_code,
            material_item_brand: row1.material_item_brand,
            material_item_uom: fg_uom || row1.material_item_uom,
            material_item_qty: qty,
            sum_of_fl_item_qty: row1.sum_of_fl_item_qty,
            fl_item_gauge: row1.fl_item_gauge,
            sum_of_duct_weight: row1.sum_of_duct_weight,
            sum_of_duct_area_with_seam: row1.sum_of_duct_area_with_seam,

            // Add these fields only if they exist in your Material Summary child table
            rate: rate,
            amount: amount
        });

        frm.add_child('costing_sheet_item', {
            item_code: row1.material_item_code,
            item_name: row1.material_item_code,
            parent_finished_goods_item: row1.parent_finished_good,
            finished_goods_item: null,
            uom: fg_uom || row1.material_item_uom,
            quantity: qty,
            rate: rate,
            amount: amount,
            item_brand: row1.material_item_brand,
            item_guage: row1.fl_item_gauge
        });
    });

    // -------------------------------
    // Accessory Items
    // -------------------------------
    (fl_doc.acc_item || []).forEach(row => {
        const so_item = find_sales_order_item(
            sales_order_items,
            row.parent_finished_good,
            row.material_item_uom
        );

        const rate = so_item ? flt(so_item.rate) : 0;
        const qty = flt(row.qty);
        const amount = qty * rate;

        frm.add_child('accessory_item', {
            item_code: row.item_code,
            item_name: row.item_name,
            uom: row.uom,
            quantity: qty,
            rate: rate,
            amount: amount
        });
    });

    frm.refresh_field('material_summary');
    frm.refresh_field('costing_sheet_item');
    frm.refresh_field('accessory_item');

    calculate_total_amount(frm);
}


function find_sales_order_item(sales_order_items, item_code, uom) {
    if (!sales_order_items || !sales_order_items.length) {
        return null;
    }

    // First priority: match item_code + uom
    let matched_item = sales_order_items.find(item =>
        item.parent_item === item_code && item.fg_item_uom === uom
    );

    // Second fallback: match only item_code
    if (!matched_item) {
        matched_item = sales_order_items.find(item =>
            item.parent_item === item_code
        );
    }

    return matched_item || null;
}
